## 5. 埋点上报工具 - track.ts

```typescript
import request from '../request';

/**
 * 埋点上报
 * @param eventName 事件名称
 * @param properties 事件属性
 */
export function track(eventName: string, properties?: Record<string, any>) {
  // 上报给后端接口
  request.post('/track', {
    event_name: eventName,
    properties: properties || {},
    device_type: 'pc',
    timestamp: Date.now(),
  }).catch(() => {
    // 埋点失败不影响用户体验，静默失败
  });
}

// 迭代1需要上报的事件:
