## 6. 错误上报工具 - errorReport.ts

```typescript
import request from '../request';

/**
 * 上报前端错误到后端
 */
export function reportError(error: Error | unknown): void {
  const errorInfo = {
    message: error instanceof Error ? error.message : String(error),
    stack: error instanceof Error ? error.stack : null,
    url: window.location.href,
    user_agent: navigator.userAgent,
    timestamp: Date.now(),
  };

  // 异步上报，不阻塞
  request.post('/error/report', errorInfo).catch(() => {
    // 静默失败不影响用户
  });
}

/**
 * 全局未捕获异常处理器
 */
export function setupGlobalErrorReporting(): void {
  window.onerror = (message, source, lineno, colno, error) => {
    reportError(error || new Error(String(message)));
    return false;
  };

  window.onunhandledrejection = (event) => {
    reportError(event.reason);
  };
}
```

