### 8.2 路由守卫实现

```typescript
// src/utils/authGuard.tsx
import { Navigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { RootState } from '../store';
import { Result, Button } from 'antd';
import React from 'react';

/**
 * 基础认证守卫 - 检查token是否存在
 */
export function authGuard(Component: React.ComponentType) {
  return () => {
    const token = useSelector((state: RootState) => state.auth.token);
    if (!token) {
      return <Navigate to="/login" replace />;
    }
    return <Component />;
  };
}

/**
 * 管理员权限守卫 - 检查用户是否是管理员
 * 后端API也会做二次权限校验，前端拦截只是提升用户体验
 */
export function adminGuard(Component: React.ComponentType) {
  return () => {
    const token = useSelector((state: RootState) => state.auth.token);
    const user = useSelector((state: RootState) => state.auth.user);

    if (!token) {
      return <Navigate to="/login" replace />;
    }

    if (!user || user.is_admin !== 1) {
      return (
        <Result
          status="403"
          title="403"
          subTitle="抱歉，您无权访问此页面"
          extra={<Button type="primary" onClick={() => window.history.back()}>返回</Button>}
        />
      );
    }

    return <Component />;
  };
}
```

**逻辑说明：**
- 所有需要认证的页面都包装在authGuard中
- 管理员页面额外包装adminGuard，检查is_admin字段
- 没有token自动跳转到登录页
- 非管理员访问管理页显示403
- 满足验收标准："未登录访问任何页面都跳转登录"

